import sys
import os
import math
import pytest
import yaml

sys.path.insert(0, os.path.join(os.path.dirname(__file__), '..'))

from astar import a_star
from graph import Graph


@pytest.fixture
def fixtures_dir():
    return os.path.join(os.path.dirname(__file__), 'fixtures')


def load_graph_fixture(fixture_path):
    '''Load a graph from a YAML fixture file.'''
    with open(fixture_path, 'r') as f:
        data = yaml.safe_load(f)

    graph = Graph(directed=False)
    vertex_map = {}

    for node_id in data['nodes']:
        vertex_map[node_id] = graph.insert_vertex(node_id)

    for edge_data in data['edges']:
        source, destination = edge_data[0], edge_data[1]
        graph.insert_edge(vertex_map[source], vertex_map[destination])

    positions = data.get('positions', {})
    return graph, vertex_map, positions


def euclidean_heuristic(vertex, goal_vertex, positions):
    '''Euclidean distance heuristic for grid-based graphs.'''
    if vertex.element() not in positions or goal_vertex.element() not in positions:
        return 0
    x1, y1 = positions[vertex.element()]
    x2, y2 = positions[goal_vertex.element()]
    return math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2)


def zero_heuristic(vertex, goal_vertex, positions):
    '''Zero heuristic (reduces A* to Dijkstra).'''
    return 0


class TestAStarSimpleGraph:
    def test_simple_path_found(self, fixtures_dir):
        '''Test A* finds a path in a simple graph.'''
        graph, vertex_map, positions = load_graph_fixture(
            os.path.join(fixtures_dir, 'simple_graph.yaml')
        )
        start = vertex_map['A']
        goal = vertex_map['D']

        def heuristic(v):
            return euclidean_heuristic(v, goal, positions)

        path, cost = a_star(graph, start, goal, heuristic)

        assert path is not None
        assert path[0] == 'A'
        assert path[-1] == 'D'
        assert cost > 0

    def test_start_equals_goal(self, fixtures_dir):
        '''Test A* when start and goal are the same.'''
        graph, vertex_map, positions = load_graph_fixture(
            os.path.join(fixtures_dir, 'simple_graph.yaml')
        )
        start = vertex_map['A']
        goal = vertex_map['A']

        def heuristic(v):
            return euclidean_heuristic(v, goal, positions)

        path, cost = a_star(graph, start, goal, heuristic)

        assert path == ['A']
        assert cost == 0

    def test_adjacent_nodes(self, fixtures_dir):
        '''Test A* finds direct edge between adjacent nodes.'''
        graph, vertex_map, positions = load_graph_fixture(
            os.path.join(fixtures_dir, 'simple_graph.yaml')
        )
        start = vertex_map['A']
        goal = vertex_map['B']

        def heuristic(v):
            return euclidean_heuristic(v, goal, positions)

        path, cost = a_star(graph, start, goal, heuristic)

        assert path == ['A', 'B']
        assert cost == 1


class TestAStarGridGraph:
    def test_grid_path(self, fixtures_dir):
        '''Test A* on a 3x3 grid graph.'''
        graph, vertex_map, positions = load_graph_fixture(
            os.path.join(fixtures_dir, 'grid_graph.yaml')
        )
        start = vertex_map[0]
        goal = vertex_map[8]

        def heuristic(v):
            return euclidean_heuristic(v, goal, positions)

        path, cost = a_star(graph, start, goal, heuristic)

        assert path is not None
        assert path[0] == 0
        assert path[-1] == 8
        # Optimal path in grid is at least 4 steps (manhattan distance)
        assert len(path) >= 5  # 5 vertices (4 edges)
        assert cost >= 4

    def test_grid_zero_heuristic(self, fixtures_dir):
        '''Test A* with zero heuristic (Dijkstra behavior) on grid.'''
        graph, vertex_map, positions = load_graph_fixture(
            os.path.join(fixtures_dir, 'grid_graph.yaml')
        )
        start = vertex_map[0]
        goal = vertex_map[8]

        def heuristic(v):
            return zero_heuristic(v, goal, positions)

        path, cost = a_star(graph, start, goal, heuristic)

        assert path is not None
        assert path[0] == 0
        assert path[-1] == 8


class TestAStarDisconnected:
    def test_no_path(self, fixtures_dir):
        '''Test A* when no path exists between start and goal.'''
        graph, vertex_map, positions = load_graph_fixture(
            os.path.join(fixtures_dir, 'disconnected_graph.yaml')
        )
        start = vertex_map['A']
        goal = vertex_map['D']

        def heuristic(v):
            return euclidean_heuristic(v, goal, positions)

        path, cost = a_star(graph, start, goal, heuristic)

        assert path is None
        assert cost == math.inf


class TestAStarWeighted:
    def test_weighted_path(self, fixtures_dir):
        '''Test A* on a weighted graph.'''
        graph, vertex_map, positions = load_graph_fixture(
            os.path.join(fixtures_dir, 'weighted_graph.yaml')
        )
        start = vertex_map['A']
        goal = vertex_map['E']

        def heuristic(v):
            return euclidean_heuristic(v, goal, positions)

        path, cost = a_star(graph, start, goal, heuristic)

        assert path is not None
        assert path[0] == 'A'
        assert path[-1] == 'E'
        assert cost > 0

    def test_weighted_shortest_path(self, fixtures_dir):
        '''Test that A* finds the shortest weighted path.'''
        graph, vertex_map, positions = load_graph_fixture(
            os.path.join(fixtures_dir, 'weighted_graph.yaml')
        )
        start = vertex_map['A']
        goal = vertex_map['D']

        def heuristic(v):
            return zero_heuristic(v, goal, positions)

        path, cost = a_star(graph, start, goal, heuristic)

        assert path is not None
